    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        adj[u].push_back({v, w});
    }

    // Dijkstra's algorithm with state (node, switch_used)
    // switch_used is 0 or 1 (0: switch not used, 1: switch used)
    priority_queue<pair<long long, pair<long long, long long>>, vector<pair<long long, pair<long long, long long>>>, greater<>> pq;
    vector<vector<long long>> dist(n, vector<long long>(2, LONG_MAX));
    dist[0][0] = 0;
    pq.push({0, {0, 0}});

    while (!pq.empty()) {
        long long cost = pq.top().first;
        long long u = pq.top().second.first;
        long long switch_used = pq.top().second.second;
        pq.pop();

        if (u == n - 1) return cost;

        if (cost > dist[u][switch_used]) continue;

        // Traverse original edges
        for (auto& [v, w] : adj[u]) {
            long long new_cost = cost + w;
            if (new_cost < dist[v][switch_used]) {
